mapper.select:
SELECT c.course_id, c.title, u.name, c.class_id, cc.class_name, c.start_date, c.end_date, c.cos_sta_code FROM course c LEFT JOIN course_class cc ON c.class_id = cc.class_id LEFT JOIN tb_userinfo u ON c.professor = u.loginID
AND c.cos_sta_code = #{cos_sta_code}
AND u.name LIKE CONCAT('%', #{searchKeyword}, '%') AND c.title LIKE CONCAT('%', #{searchKeyword}, '%')
AND (u.name LIKE CONCAT('%', #{searchKeyword}, '%') OR c.title LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY c.course_id DESC LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE course
SET cos_sta_code = #{cos_sta_code}
WHERE course_id = #{course_id}
